<?php include '../includes/db.php'; include '../includes/auth.php'; require_role('Admin'); include '../includes/header.php'; ?>

<?php if(isset($_POST['add'])){ $name=mysqli_real_escape_string($conn,$_POST['category_name']); mysqli_query($conn,"INSERT INTO categories(category_name) VALUES('$name')"); } $cats=mysqli_query($conn,"SELECT * FROM categories ORDER BY category_name"); ?>
<section class="container py-5"><h1>Manage Categories</h1><div class="row g-4"><div class="col-md-5"><div class="table-card"><form method="post"><input class="form-control mb-2" name="category_name" placeholder="Category name"><button class="btn btn-primary" name="add">Add Category</button></form></div></div><div class="col-md-7"><div class="table-card"><table class="table"><tr><th>ID</th><th>Category</th></tr><?php while($c=mysqli_fetch_assoc($cats)): ?><tr><td><?php echo $c['category_id']; ?></td><td><?php echo htmlspecialchars($c['category_name']); ?></td></tr><?php endwhile; ?></table></div></div></div></section><?php include '../includes/footer.php'; ?>
